<?php
$rows = is_array($list_so) ? $list_so : array();
$bulan = array('Januari','Februari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember');
$toko = $periode = array(); $terbaru = '';
foreach ($rows as $r) {
  $p = !empty($r->periode_ym) ? $r->periode_ym : date('Y-m', strtotime($r->tanggal));
  $toko[(string)$r->id_toko] = $r->nama_toko; $periode[$p] = true;
  if ($p > $terbaru) $terbaru = $p;
}
$namaPeriode = function($p) use ($bulan) {
  return preg_match('/^(\d{4})-(\d{2})$/', $p, $m) ? $bulan[(int)$m[2]-1].' '.$m[1] : '-';
};
?>
