<script>(function(){var q=document.getElementById('haSearch'),a=document.getElementById('haStart'),b=document.getElementById('haEnd'),rs=document.getElementById('haReset'),empty=document.getElementById('haEmpty'),count=document.getElementById('haCount'),pagination=document.getElementById('haPagination'),info=document.getElementById('haPageInfo'),label=document.getElementById('haPageCurrent'),prev=document.getElementById('haPrev'),next=document.getElementById('haNext'),rows=[].slice.call(document.querySelectorAll('[data-ha-row]')),filtered=[],page=1,size=10;function render(){var total=filtered.length,pages=Math.max(1,Math.ceil(total/size));if(page>pages)page=pages;var first=(page-1)*size,last=Math.min(first+size,total);rows.forEach(function(r){r.style.display='none'});filtered.slice(first,last).forEach(function(r,i){r.style.display='';r.querySelector('[data-number]').textContent=first+i+1});empty.style.display=total?'none':'block';pagination.style.display=total?'flex':'none';count.textContent=total+' laporan ditemukan';info.textContent=total?'Menampilkan '+(first+1)+'–'+last+' dari '+total+' laporan':'';label.textContent=page+' / '+pages;prev.disabled=page<=1;next.disabled=page>=pages}function filter(){var key=(q.value||'').toLowerCase().trim(),from=a.value,to=b.value;filtered=rows.filter(function(r){var p=r.dataset.period;return(!key||r.dataset.search.indexOf(key)>-1)&&(!from||p>=from)&&(!to||p<=to)});page=1;render()}q.addEventListener('input',filter);a.addEventListener('change',filter);b.addEventListener('change',filter);prev.addEventListener('click',function(){if(page>1){page--;render()}});next.addEventListener('click',function(){if(page*size<filtered.length){page++;render()}});rs.addEventListener('click',function(){q.value=a.value=b.value='';filter();q.focus()});filter()})();</script>
